  8636 |     case FCmpInst::FCMP_UNO:
  8637 |     case FCmpInst::FCMP_TRUE:
  8638 |     case FCmpInst::FCMP_FALSE:
  8639 |     case FCmpInst::FCMP_OGT:
  8640 |     case FCmpInst::FCMP_ULE:
  8641 |       llvm_unreachable("Should be simplified by InstSimplify");
  8642 |     case FCmpInst::FCMP_OLT:
  8643 |       return new FCmpInst(FCmpInst::FCMP_ONE, Op0, Op1, "", &I);
  8644 |     case FCmpInst::FCMP_OLE:
