  8646 |                           "", &I);
  8647 |     case FCmpInst::FCMP_OGE:
  8648 |       return new FCmpInst(FCmpInst::FCMP_OEQ, Op0, Op1, "", &I);
  8649 |     case FCmpInst::FCMP_ULT:
  8650 |       return new FCmpInst(FCmpInst::FCMP_UNE, Op0, Op1, "", &I);
  8651 |     case FCmpInst::FCMP_UGT:
