  8672 |       Value *MaskX = Builder.CreateAnd(X, ConstantInt::get(IntTy, SignMask));
  8673 |       return new ICmpInst(IntPred, MaskX, ConstantInt::getNullValue(IntTy));
  8674 |     }
  8675 |   }
