  8677 |   // Handle fcmp with instruction LHS and constant RHS.
  8678 |   Instruction *LHSI;
  8679 |   Constant *RHSC;
  8680 |   if (match(Op0, m_Instruction(LHSI)) && match(Op1, m_Constant(RHSC))) {
  8681 |     switch (LHSI->getOpcode()) {
  8682 |     case Instruction::Select:
  8683 |       // fcmp eq (cond ? x : -x), 0 --> fcmp eq x, 0
