  8735 |   // fcmp (fadd X, 0.0), Y --> fcmp X, Y
  8736 |   if (match(Op0, m_FAdd(m_Value(X), m_AnyZeroFP())))
  8737 |     return new FCmpInst(Pred, X, Op1, "", &I);
  8738 | 
  8739 |   // fcmp X, (fadd Y, 0.0) --> fcmp X, Y
  8740 |   if (match(Op1, m_FAdd(m_Value(Y), m_AnyZeroFP())))
  8741 |     return new FCmpInst(Pred, Op0, Y, "", &I);
  8742 | 
  8743 |   if (match(Op0, m_FPExt(m_Value(X)))) {
  8744 |     // fcmp (fpext X), (fpext Y) -> fcmp X, Y
  8745 |     if (match(Op1, m_FPExt(m_Value(Y))) && X->getType() == Y->getType())
  8746 |       return new FCmpInst(Pred, X, Y, "", &I);
  8747 | 
  8748 |     const APFloat *C;
  8749 |     if (match(Op1, m_APFloat(C))) {
  8750 |       const fltSemantics &FPSem =
  8751 |           X->getType()->getScalarType()->getFltSemantics();
  8752 |       bool Lossy;
  8753 |       APFloat TruncC = *C;
  8754 |       TruncC.convert(FPSem, APFloat::rmNearestTiesToEven, &Lossy);
  8755 | 
  8756 |       if (Lossy) {
  8757 |         // X can't possibly equal the higher-precision constant, so reduce any
  8758 |         // equality comparison.
  8759 |         // TODO: Other predicates can be handled via getFCmpCode().
  8760 |         switch (Pred) {
  8761 |         case FCmpInst::FCMP_OEQ:
  8762 |           // X is ordered and equal to an impossible constant --> false
  8763 |           return replaceInstUsesWith(I, ConstantInt::getFalse(I.getType()));
  8764 |         case FCmpInst::FCMP_ONE:
  8765 |           // X is ordered and not equal to an impossible constant --> ordered
  8766 |           return new FCmpInst(FCmpInst::FCMP_ORD, X,
  8767 |                               ConstantFP::getZero(X->getType()));
  8768 |         case FCmpInst::FCMP_UEQ:
  8769 |           // X is unordered or equal to an impossible constant --> unordered
  8770 |           return new FCmpInst(FCmpInst::FCMP_UNO, X,
  8771 |                               ConstantFP::getZero(X->getType()));
  8772 |         case FCmpInst::FCMP_UNE:
  8773 |           // X is unordered or not equal to an impossible constant --> true
  8774 |           return replaceInstUsesWith(I, ConstantInt::getTrue(I.getType()));
  8775 |         default:
  8776 |           break;
  8777 |         }
  8778 |       }
  8779 | 
  8780 |       // fcmp (fpext X), C -> fcmp X, (fptrunc C) if fptrunc is lossless
  8781 |       // Avoid lossy conversions and denormals.
  8782 |       // Zero is a special case that's OK to convert.
  8783 |       APFloat Fabs = TruncC;
  8784 |       Fabs.clearSign();
  8785 |       if (!Lossy &&
  8786 |           (Fabs.isZero() || !(Fabs < APFloat::getSmallestNormalized(FPSem)))) {
