  8792 | 
  8793 |   // Handle fcmp with FPTrunc LHS and constant RHS.
  8794 |   // fcmp pred (fptrunc X), C -> fcmp pred X, C'
  8795 |   // where X is a wider FP type and C' is the boundary value.
  8796 |   if (match(Op0, m_FPTrunc(m_Value(X)))) {
  8797 |     const APFloat *C;
  8798 |     if (match(Op1, m_APFloat(C))) {
