      switch (Pred) {
      case FCmpInst::FCMP_OEQ:
      case FCmpInst::FCMP_ONE:
      case FCmpInst::FCMP_UEQ:
      case FCmpInst::FCMP_UNE:
        // Equality comparisons are not safely foldable with a single boundary.
        IsBoundaryNeeded = false;
        break;
      case FCmpInst::FCMP_OGE:
      case FCmpInst::FCMP_UGE:
        // For X >= C in truncated type, we need X >= lower_bound(C) in
        // the wider type. The lower bound is C - 0.5 * ulp(C), which we
        // can get by converting C to wider type rounding toward negative.
        RM = APFloat::rmTowardNegative;
        break;
      case FCmpInst::FCMP_OLE:
      case FCmpInst::FCMP_ULE:
        // For X <= C in truncated type, we need X <= upper_bound(C) in
        // the wider type. The upper bound is C + 0.5 * ulp(C), which we
        // can get by converting C to wider type rounding toward positive.
        RM = APFloat::rmTowardPositive;
        break;
      case FCmpInst::FCMP_OGT:
      case FCmpInst::FCMP_UGT:
        // For X > C in truncated type, we need X > upper_bound(C) in
        // the wider type to ensure that fptrunc(X) will be > C.
        RM = APFloat::rmTowardPositive;
        break;
      case FCmpInst::FCMP_OLT:
      case FCmpInst::FCMP_ULT:
        // For X < C in truncated type, we need X < lower_bound(C) in
        // the wider type to ensure that fptrunc(X) will be < C.
        RM = APFloat::rmTowardNegative;
        break;
      default:
        IsBoundaryNeeded = false;
        break;
      }

