{"command": "cd /root/auto-opt/utils/llvm-85265 && cat <<'CODEEOF' | python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp 8791 8791

  // Handle fcmp with FPTrunc LHS and constant RHS.
  // fcmp pred (fptrunc X), C -> fcmp pred X, C'
  // where X is a wider FP type and C' is the inclusive boundary value.
  //
  // The key insight: fptrunc rounds to nearest representable value.
  // For ordered comparisons with a constant C in the narrower type:
  //
  // fcmp oge (fptrunc X to Ty), C -> fcmp oge X, StepDown(C)
  //   where StepDown(C) is the value just below C in Ty.
  //   If X >= StepDown(C), then fptrunc(X) >= C is true.
  //
  // fcmp ole (fptrunc X to Ty), C -> fcmp ole X, StepUp(C)
  //   where StepUp(C) is the value just above C in Ty.
  //   If X <= StepUp(C), then fptrunc(X) <= C is true.
  //
  // For strict comparisons (ogt, olt), the boundary is the same since
  // rounding to C is still possible for values strictly greater/less than C.
  if (match(Op0, m_FPTrunc(m_Value(X)))) {
    const APFloat *C;
    if (match(Op1, m_APFloat(C))) {
      Type *WideTy = X->getType();
      const fltSemantics &WideSem = WideTy->getScalarType()->getFltSemantics();

      // Skip if not a widening
      const fltSemantics &NarrowSem = OpType->getScalarType()->getFltSemantics();
      if (&WideSem == &NarrowSem)
        ;  // Same type, could be vector, continue
      else if (&NarrowSem != &APFloat::IEEEhalf() &&
               &NarrowSem != &APFloat::IEEEsingle())
        ;  // Not from half or single, continue anyway

      APFloat Boundary = *C;
      bool IsTransformable = true;

      switch (Pred) {
      case FCmpInst::FCMP_OGE:
      case FCmpInst::FCMP_UGE:
      case FCmpInst::FCMP_OGT:
      case FCmpInst::FCMP_UGT:
        // For >= or >, use the largest value just below C in narrower type.
        // StepDown = C - epsilon(C), where epsilon is the smallest gap
        // representable in the narrower type around C.
        if (C->isZero()) {
          // For +0, need smallest negative denormal.
          // Use nextDown which handles this correctly.
          Boundary = APFloat::copySign(
              APFloat::getSmallest(NarrowSem, false),  // Largest denorm magnitude
              APFloat(NarrowSem, "-0.0"));             // Negative
        } else {
          Boundary = APFloat::copySign(
              APFloat::getLargest(NarrowSem, C->isNegative()),
              APFloat(NarrowSem, C->isNegative() ? "0.0" : "-0.0"));
          // Actually, we want the value just below C in the narrower type.
          // For C > 0: we want C - 0.5*ulp(C) or the float just below C.
          // Use nextDown to get the predecessor of C.
          Boundary = APFloat(NarrowSem);
          C->copySign(Boundary);
          Boundary.copySign(*C);
          (void)Boundary.next(false);  // nextDown
        }
        // Now convert to wider type
        {
          bool LosesInfo;
          Boundary.convert(WideSem, APFloat::rmNearestTiesToEven, &LosesInfo);
        }
        break;
      case FCmpInst::FCMP_OLE:
      case FCmpInst::FCMP_ULE:
      case FCmpInst::FCMP_OLT:
