{"command": "cd /root/auto-opt/utils/llvm-85265 && cat <<'CODEEOF' | python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp 8791 8791

  // Handle fcmp with FPTrunc LHS and constant RHS.
  // fcmp pred (fptrunc X to Ty), C -> fcmp pred X, C_inclusive
  //
  // When X is truncated to a narrower type, the comparison with constant C
  // can be transformed into a comparison on X with an adjusted constant that
  // accounts for the rounding that happens during truncation.
  //
  // For OGE/UGE/OGT/UGT (>= or > comparisons), we need the smallest X such that
  // fptrunc(X) rounds to a value where the comparison holds. This is essentially
  // the "lower boundary" of values that round to something satisfying the comparison.
  //
  // For OLE/ULE/OLT/ULT (<= or < comparisons), we need the largest X such that
  // fptrunc(X) rounds to a value where the comparison holds. This is the
  // "upper boundary" of values that round appropriately.
  if (match(Op0, m_FPTrunc(m_Value(X)))) {
    const APFloat *C;
    if (match(Op1, m_APFloat(C))) {
      Type *SrcTy = X->getType();
      const fltSemantics &SrcSem = SrcTy->getScalarType()->getFltSemantics();
      const fltSemantics &NarrowSem = OpType->getScalarType()->getFltSemantics();

      // Only handle conversions from wider to narrower FP types.
      if (&SrcSem != &NarrowSem &&
          ((&NarrowSem == &APFloat::IEEEhalf() &&
            &SrcSem == &APFloat::IEEEdouble()) ||
           (&NarrowSem == &APFloat::IEEEsingle() &&
            &SrcSem == &APFloat::IEEEdouble()) ||
           (&NarrowSem == &APFloat::IEEEhalf() &&
            &SrcSem == &APFloat::IEEEquad()) ||
           (&NarrowSem == &APFloat::IEEEsingle() &&
            &SrcSem == &APFloat::IEEEquad()))) {

        APFloat Boundary = *C;
        bool IsTransformable = true;
        bool UseLowerBound = false;

        switch (Pred) {
        case FCmpInst::FCMP_OGE:
        case FCmpInst::FCMP_UGE:
        case FCmpInst::FCMP_OGT:
        case FCmpInst::FCMP_UGT:
          UseLowerBound = true;
          break;
        case FCmpInst::FCMP_OLE:
        case FCmpInst::FCMP_ULE:
        case FCmpInst::FCMP_OLT:
        case FCmpInst::FCMP_ULT:
          UseLowerBound = false;
          break;
        default:
          IsTransformable = false;
          break;
        }

        if (IsTransformable) {
          bool LosesInfo;
          APFloatBase::roundingMode RM = UseLowerBound
                                             ? APFloat::rmTowardNegative
                                             : APFloat::rmTowardPositive;
          // Convert the float constant to double using appropriate rounding.
          // The rounding mode captures the boundary: toward negative gives us
          // values that will definitely satisfy >=, toward positive gives
          // values that will definitely satisfy <=.
          Boundary.convert(SrcSem, RM, &LosesInfo);

          if (Boundary.isFinite()) {
            Constant *NewC = ConstantFP::get(SrcTy, Boundary);
            return new FCmpInst(Pred, X, NewC, "", &I);
          }
        }
      }
    }
  }
CODEEOF"}

